messages.content:
RISKS:
[
 {
  "riskId": "risk.ledger-self-audit.framework-agreements-hollow-large-operator-cell",
  "title": "Global framework agreements and bundled fit-outs foreclose the 0.40 large-operator cell the whole GTM is aimed at",
  "claim": "The venture's stated first buyer is large operators, and cust.operator-large carries the biggest single channel weight (0.40) — a needs-source internal estimate with two-decimal precision. The corpus shows what that cell actually looks like from inside procurement: PDU spend at large operators flows through multi-year global framework agreements and integrated rack/power/cooling bundles (Digital Realty–Schneider style frameworks, all-in integrator contracts), not discrete PDU line items a regional entrant can bid. If half the 0.40 is procured this way, the model's most reachable-looking cell is structurally closed in Year 1 — and the conservative 1% obtainableFactor is being applied to a SAM that contains spend no entrant can contest at any price.",
  "falsifier": "Three or more CE large-operator PDU procurements in the next 12 months run as discrete, multi-vendor bake-offs and won by vendors outside the incumbent framework holders."
 },
 {
  "riskId": "risk.ledger-self-audit.europe-thirty-percent-arithmetic-ghost",
  "title": "A hostile reviewer strikes the unsourced 'Europe ≈ 30%' hop and the €300M loses its floor, not just its band",
  "claim": "The tamBase derivation looks disciplined — a refinement cycle even killed a contaminated €495M ceiling. But its load-bearing hop, 'Europe ≈ 30% of global', is an inserted analyst estimate: Grand View publishes only North America's 38% and no source in any search pass gives a Europe or CE rack-PDU figure. Worse, the global anchor itself is unsettled — same-category estimates run from $1.697B to $5.3B (QY Research $3.255B and Strategic Market Research $5.3B sit in this venture's own digest), a spread wider than the model's ±20% band. A diligence partner strikes the 30%, pairs the lowest credible global anchor with a conservative Europe share, and lands near €200M — below the band's floor — and the model has no sourced fact with which to push back. The band communicates 'we've bounded the uncertainty'; the derivation chain shows the uncertainty was never bounded, only anchored to one publisher's number times an invented ratio.",
  "falsifier": "The commissioned IndexBox EU rack-PDU country tables (the ledger's own named promotion path) placing the CE-7 base at €270M or above."
 },
 {
  "riskId": "risk.ledger-self-audit.oem-cell-double-squeeze-foreclosure",
  "title": "The 0.22 OEM/integrator cell is squeezed from both sides — branded incumbents win the spec, Taiwanese ODMs win the white-label — leaving no seat for a CE entrant",
  "claim": "cust.oem carries 0.22 of the buyer mix with no derivation, no evidence rows, and needs-source maturity — yet it silently props up 22% of the SAM as a fallback channel if large operators prove hard. The corpus says the cell is real but not contestable: every integrator case study found shows integrators selecting branded incumbents on certification, DCIM compatibility and support, while the actual white-label volume is already served by established OEM/ODM specialists (Digipower-class manufacturers) competing on Asian cost structures. A new CE industrial entrant is neither the trusted brand nor the cost-floor ODM. This is not a smaller cell — it is a cell that exists for other players, which is why the correct model operation is exclusion, not shrinkage.",
  "falsifier": "Two CE rack integrators or master distributors confirming open white-label PDU sourcing rounds with a realistic qualification path for a new regional manufacturer at viable margins."
 },
 {
  "riskId": "risk.ledger-self-audit.nl-frozen-colo-stock-share-decay",
  "title": "NL's 0.28 is a share of a stock that regulation has frozen — growth migrates to self-build hyperscale the entrant reaches through a different (foreclosed) door",
  "claim": "geo.NL looks like the model's safest node: Statista and the Dutch Data Center Association agree within 3%. But both measure the same thing — the existing colo stock — and that stock is capped: Amsterdam's 350 MVA ceiling and grid connections unavailable until 2030 freeze the region holding ~70% of Dutch colo capacity, while NL hyperscale self-build grows at a forecast ~26% CAGR against colo's ~3.5%. The 0.28 therefore describes where the market was, not where the next five years of PDU purchase orders will originate. Worse, the demand that does grow in NL arrives via hyperscale self-build procurement — exactly the framework-locked channel already flagged as least contestable — so the entrant's effective NL opportunity decays on two axes at once: the reachable segment shrinks and the growing segment is behind a closed door.",
  "falsifier": "2026 Statista/DDA updates showing NL colocation MW additions at or above the CE-7 average rate, alongside evidence of Amsterdam-region grid connections being granted before 2030."
 },
 {
  "riskId": "risk.execution-window.som-window-semantics-year1-zero",
  "title": "The 1% Year-1 anchor is a 36-month accrual read as an annual snapshot — the pre-launch clock makes even that generous",
  "claim": "obtainableFactor's 1% was 'corrected' in refinement cycle 1 and now looks conservative and triangulated. But the benchmark corpus it leans on defines SOM as a 1–3 year (Prospeo, IdeaPlan) or 3–5 year (Wise) cumulative capture, not a Year-1 run-rate, and the one worked example in the corpus lands at 0.1% of SAM — 5x below the band's own floor. Layer the venture's actual clock on top: it is pre-launch, so months 1–6 are certification, listing and pipeline-building, not selling. A 'conservative ramp' that books its first PO in month 7–9 doesn't earn 1% of SAM; it earns a fraction of the back half of the year. The band's low edge (0.5%) is not the pessimistic case — it is the optimistic reading of the sources' own semantics.",
  "falsifier": "A comparable early-stage DC-hardware entrant (intelligent PDU or adjacent rack power gear) documented capturing ≥1% of its serviceable market within its first 12 calendar months from launch."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
